# Logic Gates Implementation in Python

def NOT(a):
    return not a

def AND(a, b):
    return a and b

def OR(a, b):
    return a or b

def NAND(a, b):
    return not (a and b)

def NOR(a, b):
    return not (a or b)

def XOR(a, b):
    return (a and not b) or (not a and b)

def XNOR(a, b):
    return not XOR(a, b)

