#include <stdio.h>

// Logic gate functions
int NOT(int a) { return !a; }
int AND(int a, int b) { return a && b; }
int OR(int a, int b) { return a || b; }
int NAND(int a, int b) { return !(a && b); }
int NOR(int a, int b) { return !(a || b); }
int XOR(int a, int b) { return (a && !b) || (!a && b); }
int XNOR(int a, int b) { return !XOR(a, b); }

int main() {
    printf("A B | NOT AND OR NAND NOR XOR XNOR\n");
    printf("--------------------------------------\n");

    for (int a = 0; a <= 1; a++) {
        for (int b = 0; b <= 1; b++) {
            printf("%d %d |  %d   %d   %d    %d    %d    %d    %d\n",
                a, b,
                NOT(a), AND(a,b), OR(a,b),
                NAND(a,b), NOR(a,b), XOR(a,b), XNOR(a,b));
        }
    }
    return 0;
}

public class NANDGateImplementation {

    // Basic NAND gate
    public static boolean NAND(boolean a, boolean b) {
        return !(a && b);
    }

    // Implement NOT using NAND
    public static boolean NOT(boolean a) {
        return NAND(a, a);  // NAND(a, a) = a'
    }

    // Implement AND using NAND
    public static boolean AND(boolean a, boolean b) {
        return NOT(NAND(a, b));  // NAND(a,b)' = a·b
    }

    // Implement OR using NAND (using De Morgan)
    public static boolean OR(boolean a, boolean b) {
        return NAND(NOT(a), NOT(b));  // a' NAND b' = a + b
    }

    // Implement NOR using NAND
    public static boolean NOR(boolean a, boolean b) {
        return NOT(OR(a, b));
    }

    // Implement XOR using NAND
    public static boolean XOR(boolean a, boolean b) {
        boolean nand_ab = NAND(a, b);
        boolean nand_a = NAND(a, nand_ab);
        boolean nand_b = NAND(b, nand_ab);
        return NAND(nand_a, nand_b);
    }

    public static void main(String[] args) {
        // Test all gates implemented using only NAND
        System.out.println("A B | NOT | AND | OR | XOR");
        for (int a = 0; a <= 1; a++) {
            for (int b = 0; b <= 1; b++) {
                boolean A = (a == 1), B = (b == 1);
                System.out.println(a + " " + b + " |  " + 
                    (NOT(A) ? 1 : 0) + "  |  " + 
                    (AND(A, B) ? 1 : 0) + "  |  " + 
                    (OR(A, B) ? 1 : 0) + "  |  " + 
                    (XOR(A, B) ? 1 : 0));
            }
        }
    }
}
